// generar_244_tips_menos_ruido.js
// CHIQUI Entre Señales — ChiquiTips: menos altura, menos ruido visual
//
// Ajuste sobre el 243 basado en revisión UX/UI. Diagnóstico:
// - Las tarjetas cerradas quedaban demasiado altas (190 px): había
//   aire vacío arriba y abajo, se veían "infladas". El grid parejo
//   se logra con ritmo visual, no con altura.
// - Los cuadros verde y rojo dentro de HAZ / EVITA generaban
//   "tarjeta-dentro-de-tarjeta" — competían con el contenedor
//   principal y saturaban visualmente. El semáforo puede vivir en un
//   ACENTO LATERAL, no en un fondo completo.
//
// Cambios:
// 1) Altura fija cerrada: 190 → 150 px. El ritmo se mantiene porque
//    las preguntas ya son cortas y homogéneas (rango 23-41 chars);
//    aire justo, cero relleno.
// 2) Signos de alerta al expandir:
//    - Fuera los cuadros de fondo verde/rojo y sus emojis decorativos.
//    - Cada bloque tiene una barra vertical de 2.5 px a la izquierda
//      (verde para HAZ, rojo para EVITA) + su etiqueta pequeña en
//      mayúsculas del color respectivo. Limpio, jerárquico, escaneable.
//    - "Cómo reconocerlo" queda como intro breve en cursiva, sin la
//      etiqueta previa — se lee natural.
//
// Filosofía: en móvil el espacio ES el diseño. Cuando algo se ve mal
// casi siempre es porque hay más de lo necesario. Esta versión tiene
// MENOS que la anterior, y por eso se ve mejor.
//
// Solo reescribe components/ChiquiTeCuenta.tsx. No hay SQL.
//
// Uso:
//   node generar_244_tips_menos_ruido.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'components/ChiquiTeCuenta.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
